190→    @SuppressWarnings("unused")
191→    @Subscribe(threadMode = ThreadMode.MAIN)
192→    public void onCommentChanged(OnCommentChanged event) {
193→        if (mBinding != null) {
194→            mIsUpdatingComments = false;
195→            setLoadingState(mBinding, false);
196→            // Don't refresh the list on push, we already updated comments
197→            if (event.causeOfChange != CommentAction.PUSH_COMMENT) {
198→                if (event.changedCommentsLocalIds.size() > 0) {
199→                    loadDataInViewPager(mBinding);
200→                } else if (!event.isError()) {
201→                    // There are no more comments to load
202→                    mCanLoadMoreComments = false;
203→                }
204→            }
205→            if (event.isError()) {
206→                if (!TextUtils.isEmpty(event.error.message)) {
207→                    ToastUtils.showToast(this, event.error.message);
208→                }
209→            }
210→        }
211→    }
