213→    @SuppressWarnings("deprecation")
214→    private void loadDataInViewPager(@NonNull CommentsDetailActivityBinding binding) {
215→        if (mIsLoadingComments) {
216→            AppLog.w(AppLog.T.COMMENTS, "load comments task already active");
217→        } else {
218→            new LoadCommentsTask(mCommentsStoreAdapter, mStatusFilter, mSite, new LoadCommentsTask.LoadingCallback() {
219→                @Override
220→                public void isLoading(boolean loading) {
221→                    setLoadingState(binding, loading);
222→                    mIsLoadingComments = loading;
223→                }
224→
225→                @Override
226→                public void loadingFinished(CommentList commentList) {
227→                    if (!commentList.isEmpty()) {
228→                        showCommentList(binding, commentList);
229→                    }
230→                }
231→            }).executeOnExecutor(AsyncTask.THREAD_POOL_EXECUTOR);
232→        }
