256→            }
257→        }
258→
259→        final int commentIndex = mAdapter.commentIndex(mCommentId);
260→        if (commentIndex < 0) {
261→            showErrorToastAndFinish();
262→        }
263→        if (mOnPageChangeListener != null) {
264→            binding.viewpager.removeOnPageChangeListener(mOnPageChangeListener);
265→        } else {
266→            mOnPageChangeListener = new ViewPager.SimpleOnPageChangeListener() {
267→                @Override
