 60→@Suppress("LongParameterList")
 61→class PostActionHandler(
 62→    private val dispatcher: Dispatcher,
 63→    private val site: SiteModel,
 64→    private val postStore: PostStore,
 65→    private val postListDialogHelper: PostListDialogHelper,
 66→    private val doesPostHaveUnhandledConflict: (PostModel) -> Boolean,
 67→    private val hasUnhandledAutoSave: (PostModel) -> Boolean,
 68→    private val triggerPostListAction: (PostListAction) -> Unit,
 69→    private val triggerPostUploadAction: (PostUploadAction) -> Unit,
 70→    private val triggerPublishAction: (PostModel) -> Unit,
 71→    private val invalidateList: () -> Unit,
 72→    private val checkNetworkConnection: () -> Boolean,
 73→    private val showSnackbar: (SnackbarMessageHolder) -> Unit,
 74→    private val showToast: (ToastMessageHolder) -> Unit,
 75→    private val triggerPreviewStateUpdate: (PostListRemotePreviewState, PostInfoType) -> Unit,
 76→    private val copyPost: (SiteModel, PostModel, Boolean) -> Unit
 77→) {
 78→    private val criticalPostActionTracker = CriticalPostActionTracker(onStateChanged = {
 79→        invalidateList.invoke()
 80→    })
 81→
 82→    fun handlePostButton(buttonType: PostListButtonType, post: PostModel, hasAutoSave: Boolean) {
 83→        when (buttonType) {
 84→            BUTTON_EDIT -> editPostButtonAction(site, post)
 85→            BUTTON_RETRY -> triggerPostListAction.invoke(RetryUpload(post))
 86→            BUTTON_MOVE_TO_DRAFT -> {
 87→                moveTrashedPostToDraft(post)
 88→            }
 89→            BUTTON_PUBLISH -> {
 90→                triggerPublishAction.invoke(post)
 91→            }
 92→            BUTTON_SYNC -> {
 93→                postListDialogHelper.showSyncScheduledPostConfirmationDialog(post)
 94→            }
 95→            BUTTON_SUBMIT -> publishPost(post.id)
 96→            BUTTON_VIEW -> triggerPostListAction.invoke(ViewPost(site, post))
 97→            BUTTON_PREVIEW -> triggerPostListAction.invoke(
 98→                PreviewPost(
 99→                    site = site,
100→                    post = post,
101→                    triggerPreviewStateUpdate = triggerPreviewStateUpdate,
102→                    showToast = showToast,
103→                    messageMediaUploading = ToastMessageHolder(
104→                        R.string.editor_toast_uploading_please_wait,
105→                        Duration.SHORT
106→                    )
107→                )
108→            )
109→            BUTTON_STATS -> triggerPostListAction.invoke(ViewStats(site, post))
110→            BUTTON_TRASH -> {
111→                when {
112→                    post.isLocallyChanged -> {
113→                        postListDialogHelper.showTrashPostWithLocalChangesConfirmationDialog(post)
114→                    }
115→                    hasAutoSave -> {
116→                        postListDialogHelper.showTrashPostWithUnsavedChangesConfirmationDialog(post)
117→                    }
118→                    else -> trashPost(post)
119→                }
120→            }
121→            BUTTON_COPY -> copyPost(site, post, true)
122→            BUTTON_COPY_URL -> triggerPostListAction.invoke(copyUrlAction(post))
123→            BUTTON_DELETE, BUTTON_DELETE_PERMANENTLY -> {
124→                postListDialogHelper.showDeletePostConfirmationDialog(post)
125→            }
126→            BUTTON_CANCEL_PENDING_AUTO_UPLOAD -> {
127→                cancelPendingAutoUpload(post)
128→            }
129→            BUTTON_SHOW_MOVE_TRASHED_POST_TO_DRAFT_DIALOG -> {
130→                postListDialogHelper.showMoveTrashedPostToDraftDialog(post)
131→            }
132→            BUTTON_MORE -> {
133→            } // do nothing - ui will show a popup window
134→            BUTTON_PROMOTE_WITH_BLAZE -> {
135→                triggerPostListAction.invoke(PostListAction.ShowPromoteWithBlaze(post))
136→            }
137→            BUTTON_COMMENTS -> {
138→                triggerPostListAction.invoke(PostListAction.ViewComments(site, post))
139→            }
140→        }
141→    }
142→
143→    private fun copyUrlAction(post: PostModel) = PostListAction.CopyUrl(
144→        site = site,
145→        post = post,
146→        showSnackbar = showSnackbar,
147→        messageSuccess = SnackbarMessageHolder(
148→            UiStringRes(R.string.post_link_copied_to_clipboard),
149→            duration = Snackbar.LENGTH_SHORT,
150→            isImportant = false
151→        ),
152→        messageError = SnackbarMessageHolder(
153→            UiStringRes(R.string.error_copy_to_clipboard),
154→            duration = Snackbar.LENGTH_SHORT,
155→            isImportant = false
156→        )
157→    )
158→
159→    private fun cancelPendingAutoUpload(post: PostModel) {
160→        val msgRes = UploadUtils.cancelPendingAutoUpload(post, dispatcher)
161→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(msgRes)))
162→    }
163→
164→    fun newPost() {
165→        triggerPostListAction(PostListAction.NewPost(site))
166→    }
167→
168→    fun newStoryPost() {
169→        triggerPostListAction(PostListAction.NewStoryPost(site))
170→    }
171→
172→    fun handleEditPostResult(data: Intent?) {
173→        val localPostId = data?.getIntExtra(EditPostActivity.EXTRA_POST_LOCAL_ID, 0)
174→        if (localPostId == null || localPostId == 0) {
175→            return
176→        }
177→        val post = postStore.getPostByLocalPostId(localPostId)
178→        if (post != null) {
179→            triggerPostUploadAction(EditPostResult(site, post, data) { publishPost(localPostId) })
180→        }
181→    }
182→
183→    fun handleRemotePreview(localPostId: Int, remotePreviewType: RemotePreviewType) {
184→        val post = postStore.getPostByLocalPostId(localPostId)
185→        if (post != null) {
186→            triggerPostListAction.invoke(PostListAction.RemotePreviewPost(site, post, remotePreviewType))
187→        }
188→    }
189→
190→    fun publishPost(localPostId: Int) {
191→        val post = postStore.getPostByLocalPostId(localPostId)
192→        if (post != null) {
193→            triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
194→        }
195→    }
196→
197→    fun publishPost(post: PostModel) {
198→        triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
199→    }
200→
201→    fun resolveConflictsAndEditPost(localPostId: Int) {
202→        val post = postStore.getPostByLocalPostId(localPostId)
203→        if (post != null) {
204→            performChecksAndEdit(site, post)
205→        }
206→    }
207→
208→    fun moveTrashedPostToDraft(localPostId: Int) {
209→        val post = postStore.getPostByLocalPostId(localPostId)
210→        if (post != null) {
211→            moveTrashedPostToDraft(post)
212→        }
213→    }
214→
215→    private fun moveTrashedPostToDraft(post: PostModel) {
216→        /*
217→         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
218→         * but that'll leave the trashed post in the remote which can be confusing.
219→         */
220→        if (!checkNetworkConnection.invoke()) {
221→            return
222→        }
223→        post.setStatus(DRAFT.toString())
224→        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
225→
226→        val localPostId = LocalId(post.id)
227→        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
228→
229→        val snackBarHolder = SnackbarMessageHolder(
230→            message = UiStringRes(R.string.post_moving_to_draft),
231→            onDismissAction = {
232→                criticalPostActionTracker.remove(localPostId, MOVING_POST_TO_DRAFT)
233→            }
234→        )
235→        showSnackbar.invoke(snackBarHolder)
236→    }
237→
238→    private fun editPostButtonAction(site: SiteModel, post: PostModel) = performChecksAndEdit(site, post)
239→
240→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
241→        // first of all, check whether this post is in Conflicted state with a more recent remote version
242→        if (doesPostHaveUnhandledConflict.invoke(post)) {
243→            postListDialogHelper.showConflictedPostResolutionDialog(post)
244→            return
245→        }
246→
247→        // Then check if an autosave revision is available
248→        if (hasUnhandledAutoSave.invoke(post)) {
249→            postListDialogHelper.showAutoSaveRevisionDialog(post)
250→            return
251→        }
252→
253→        editPost(site, post)
254→    }
255→
256→    private fun editPost(site: SiteModel, post: PostModel) {
257→        if (UploadService.isPostUploadingOrQueued(post)) {
258→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
259→            // post itself when they finish (since we're about to edit it again)
260→            UploadService.cancelQueuedPostUpload(post)
261→        }
262→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
263→    }
264→
265→    fun deletePost(localPostId: Int) {
266→        // If post doesn't exist, nothing else to do
267→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
268→        criticalPostActionTracker.add(LocalId(post.id), DELETING_POST)
269→
270→        when {
271→            post.isLocalDraft -> {
