240→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
241→        // first of all, check whether this post is in Conflicted state with a more recent remote version
242→        if (doesPostHaveUnhandledConflict.invoke(post)) {
243→            postListDialogHelper.showConflictedPostResolutionDialog(post)
244→            return
245→        }
246→
247→        // Then check if an autosave revision is available
248→        if (hasUnhandledAutoSave.invoke(post)) {
249→            postListDialogHelper.showAutoSaveRevisionDialog(post)
250→            return
251→        }
252→
253→        editPost(site, post)
254→    }
