256→    private fun editPost(site: SiteModel, post: PostModel) {
257→        if (UploadService.isPostUploadingOrQueued(post)) {
258→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
259→            // post itself when they finish (since we're about to edit it again)
260→            UploadService.cancelQueuedPostUpload(post)
261→        }
262→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
263→    }
