265→    fun deletePost(localPostId: Int) {
266→        // If post doesn't exist, nothing else to do
267→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
268→        criticalPostActionTracker.add(LocalId(post.id), DELETING_POST)
269→
270→        when {
271→            post.isLocalDraft -> {
272→                val pushId = PendingDraftsNotificationsUtils.makePendingDraftNotificationId(post.id)
273→                triggerPostListAction(DismissPendingNotification(pushId))
274→                dispatcher.dispatch(PostActionBuilder.newRemovePostAction(post))
275→            }
276→            else -> {
277→                dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
278→            }
279→        }
280→    }
