282→    /**
283→     * This function handles a post being deleted and removed. Since deleting remote posts will trigger both delete
284→     * and remove actions we only want to remove the critical action when the post is actually successfully removed.
285→     *
286→     * It's possible to separate these into two methods that handles delete and remove. However, the fact that they
287→     * follow the same approach and the tricky nature of delete action makes combining the actions like so makes our
288→     * expectations clearer.
289→     */
290→    fun handlePostDeletedOrRemoved(localPostId: LocalId, isRemoved: Boolean, isError: Boolean) {
291→        if (criticalPostActionTracker.get(localPostId) != DELETING_POST) {
292→            /*
293→             * This is an unexpected action and either it has already been handled or another critical action has
294→             * been performed. In either case, safest action is to just ignore it.
295→             */
296→            return
297→        }
298→        if (isError) {
299→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
300→        }
301→        if (isRemoved) {
302→            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
303→        }
304→    }
