317→    private fun trashPost(post: PostModel, hasLocalChanges: Boolean = false) {
318→        // We need network connection to trash a post
319→        if (!checkNetworkConnection()) {
320→            return
321→        }
322→        val criticalPostAction = if (hasLocalChanges) {
323→            TRASHING_POST_WITH_LOCAL_CHANGES
324→        } else {
325→            TRASHING_POST
326→        }
327→
328→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(R.string.post_trashing)))
329→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = criticalPostAction)
330→
331→        triggerPostUploadAction.invoke(CancelPostAndMediaUpload(post))
332→        dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
333→    }
