335→    @Suppress("UseCheckOrError")
336→    fun handlePostTrashed(localPostId: LocalId, isError: Boolean) {
337→        val criticalAction = criticalPostActionTracker.get(localPostId)
338→        if (criticalAction != TRASHING_POST && criticalAction != TRASHING_POST_WITH_LOCAL_CHANGES) {
339→            /*
340→             * This is an unexpected action and either it has already been handled or another critical action has
341→             * been performed. In either case, safest action is to just ignore it.
342→             */
343→            return
344→        }
345→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = criticalAction)
346→        if (isError) {
347→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
348→        } else {
349→            val snackBarHolder = when (criticalAction) {
350→                TRASHING_POST -> SnackbarMessageHolder(
351→                    message = UiStringRes(R.string.post_trashed),
352→                    buttonTitle = UiStringRes(R.string.undo),
353→                    buttonAction = {
354→                        val post = postStore.getPostByLocalPostId(localPostId.value)
355→                        if (post != null) {
356→                            restorePost(post)
357→                        }
358→                    }
359→                )
360→                TRASHING_POST_WITH_LOCAL_CHANGES -> SnackbarMessageHolder(message = UiStringRes(R.string.post_trashed))
361→                else -> throw IllegalStateException("Unexpected action in handlePostTrashed(): $criticalAction")
362→            }
363→            showSnackbar.invoke(snackBarHolder)
364→        }
365→    }
